   1 | import { createRequire } from "node:module";
   2 | 
   3 | const cjkRequire = createRequire(import.meta.url);
   4 | 
   5 | const CJK_RE = /[\p{Script=Han}\p{Script=Hiragana}\p{Script=Katakana}\p{Script=Hangul}]/u;
   6 | const HAN_RE = /\p{Script=Han}/u;
   7 | const KANA_RE = /[\p{Script=Hiragana}\p{Script=Katakana}]/u;
   8 | const HANGUL_RE = /\p{Script=Hangul}/u;
   9 | const CJK_RUN_RE = /[\p{Script=Han}\p{Script=Hiragana}\p{Script=Katakana}\p{Script=Hangul}]+/gu;
  10 | const HANGUL_BLOCK_RE = /[가-힯]+/g;
  11 | 
  12 | type Script = "han" | "kana" | "hangul" | "other";
  13 | 
  14 | const hintShown = new Set<string>();
  15 | 
  16 | export function hasCjk(text: string): boolean {
  17 |   return CJK_RE.test(text);
  18 | }
  19 | 
  20 | export function detectScript(text: string): Script {
  21 |   if (HAN_RE.test(text)) return "han";
  22 |   if (KANA_RE.test(text)) return "kana";
  23 |   if (HANGUL_RE.test(text)) return "hangul";
  24 |   return "other";
  25 | }
  26 | 
  27 | function showHintOnce(key: string, message: string): void {
  28 |   if (hintShown.has(key)) return;
  29 |   hintShown.add(key);
  30 |   if (typeof process !== "undefined" && process.stderr?.write) {
  31 |     process.stderr.write(`agentmemory: ${message}\n`);
  32 |   }
  33 | }
  34 | 
  35 | interface JiebaInstance {
  36 |   cut(text: string, hmm?: boolean): string[];
  37 | }
  38 | 
  39 | let jiebaInstance: JiebaInstance | null = null;
  40 | let jiebaLoaded = false;
  41 | 
  42 | function getJieba(): JiebaInstance | null {
  43 |   if (jiebaLoaded) return jiebaInstance;
  44 |   jiebaLoaded = true;
  45 |   try {
  46 |     const mod = cjkRequire("@node-rs/jieba") as {
  47 |       Jieba: {
  48 |         new (): JiebaInstance;
  49 |         withDict(dict: Uint8Array): JiebaInstance;
  50 |       };
  51 |     };
  52 |     try {
  53 |       const dictMod = cjkRequire("@node-rs/jieba/dict") as { dict: Uint8Array };
  54 |       jiebaInstance = mod.Jieba.withDict(dictMod.dict);
  55 |     } catch {
  56 |       jiebaInstance = new mod.Jieba();
  57 |     }
  58 |     return jiebaInstance;
  59 |   } catch {
  60 |     showHintOnce(
  61 |       "jieba",
  62 |       "install @node-rs/jieba to improve Chinese search; falling back to whole-string tokenization",
  63 |     );
  64 |     return null;
  65 |   }
  66 | }
  67 | 
  68 | interface JaSegmenter {
  69 |   segment(text: string): string[];
  70 | }
  71 | 
  72 | let jaSegmenterInstance: JaSegmenter | null = null;
  73 | let jaSegmenterLoaded = false;
  74 | 
  75 | function getJaSegmenter(): JaSegmenter | null {
  76 |   if (jaSegmenterLoaded) return jaSegmenterInstance;
  77 |   jaSegmenterLoaded = true;
  78 |   try {
  79 |     const Ctor = cjkRequire("tiny-segmenter") as new () => JaSegmenter;
  80 |     jaSegmenterInstance = new Ctor();
  81 |     return jaSegmenterInstance;
  82 |   } catch {
  83 |     showHintOnce(
  84 |       "tiny-segmenter",
  85 |       "install tiny-segmenter to improve Japanese search; falling back to whole-string tokenization",
  86 |     );
  87 |     return null;
  88 |   }
  89 | }
  90 | 
  91 | function cleanTokens(tokens: string[]): string[] {
  92 |   const out: string[] = [];
  93 |   for (const t of tokens) {
  94 |     const trimmed = t.trim();
  95 |     if (trimmed) out.push(trimmed);
  96 |   }
  97 |   return out;
  98 | }
  99 | 
 100 | function segmentHan(text: string): string[] {
 101 |   const j = getJieba();
 102 |   if (!j) return [text];
 103 |   try {
 104 |     return cleanTokens(j.cut(text, true));
 105 |   } catch {
 106 |     return [text];
 107 |   }
 108 | }
 109 | 
 110 | function segmentKana(text: string): string[] {
 111 |   const s = getJaSegmenter();
 112 |   if (!s) return [text];
 113 |   try {
 114 |     return cleanTokens(s.segment(text));
 115 |   } catch {
 116 |     return [text];
 117 |   }
 118 | }
